# solution.py
"""Team_Collaboration_Manager - a collaborative team/project management core.

This module provides an in-memory, thread-safe management layer for users,
projects, tasks, messaging, performance dashboards and reporting.  All public
operations are exposed through :class:`TeamCollaborationManager`.

The implementation is dependency free (standard library only) and is designed
to be embedded behind a web layer.  Identifiers are globally unique across all
entity types and are generated atomically under a shared lock so that the
manager behaves correctly under concurrent access.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Set


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Role a user can hold within the platform."""

    MEMBER = "member"
    ADMIN = "admin"
    GUEST = "guest"


class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Export formats supported by the reporting engine."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of report the engine can produce."""

    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal stores (data containers that share the manager's lock)
# ---------------------------------------------------------------------------
class _BaseStore:
    """A simple data container that exposes the shared concurrency lock."""

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self.items: Dict[int, User] = {}
        self.by_username: Dict[str, int] = {}
        self.by_email: Dict[str, int] = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self.items: Dict[int, Project] = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self.items: Dict[int, Task] = {}
        self.by_project: Dict[int, List[int]] = {}
        self.by_assignee: Dict[int, Set[int]] = {}


class _MessageStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self.items: Dict[int, Message] = {}
        self.by_project: Dict[int, List[int]] = {}
        self.by_task: Dict[int, List[int]] = {}


class _PerformanceStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self.ratings: Dict[int, Rating] = {}
        self.by_ratee: Dict[int, List[int]] = {}


class _ReportStore(_BaseStore):
    """Reporting is stateless; it only needs the shared lock."""


def _default_now() -> datetime:
    return datetime.now()


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Thread-safe, in-memory collaboration manager.

    Parameters
    ----------
    now:
        Optional zero-argument callable returning the "current" datetime.  It
        is used everywhere a timestamp is required, allowing deterministic
        testing via an injected clock.  Defaults to :func:`datetime.now`.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now_fn: Callable[[], datetime] = now if now is not None else _default_now
        self._lock = threading.RLock()
        self._id_counter = 0

        # Sub-stores all share the single manager lock.
        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- internal helpers ---------------------------------------------------
    def _now(self) -> datetime:
        return self._now_fn()

    def _new_id(self) -> int:
        with self._lock:
            self._id_counter += 1
            return self._id_counter

    @staticmethod
    def _clone(obj):
        return copy.deepcopy(obj)

    @staticmethod
    def _validate_nonempty(value, label):
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} must be a non-empty string".format(label))
        return value.strip()

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("invalid email address")
        return cleaned

    @staticmethod
    def _validate_dates(start_date, end_date):
        if start_date is None or end_date is None:
            raise ValidationError("start_date and end_date are required")
        if end_date < start_date:
            raise ValidationError("end_date cannot be before start_date")

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        username = self._validate_nonempty(username, "username")
        email = self._validate_email(email)
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")
        with self._lock:
            if username in self.users.by_username:
                raise DuplicateError("username already in use")
            if email in self.users.by_email:
                raise DuplicateError("email already in use")
            uid = self._new_id()
            user = User(
                id=uid,
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users.items[uid] = user
            self.users.by_username[username] = uid
            self.users.by_email[email] = uid
            return self._clone(user)

    def get_user(self, user_id):
        with self._lock:
            user = self.users.items.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))
            return self._clone(user)

    def list_users(self):
        with self._lock:
            ordered = sorted(self.users.items.values(), key=lambda u: u.id)
            return [self._clone(u) for u in ordered]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self.users.items.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))

            new_username = user.username
            new_email = user.email
            new_role = user.role

            if username is not None:
                new_username = self._validate_nonempty(username, "username")
            if email is not None:
                new_email = self._validate_email(email)
            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            if new_username != user.username:
                existing = self.users.by_username.get(new_username)
                if existing is not None and existing != user_id:
                    raise DuplicateError("username already in use")
            if new_email != user.email:
                existing = self.users.by_email.get(new_email)
                if existing is not None and existing != user_id:
                    raise DuplicateError("email already in use")

            if new_username != user.username:
                self.users.by_username.pop(user.username, None)
                self.users.by_username[new_username] = user_id
                user.username = new_username
            if new_email != user.email:
                self.users.by_email.pop(user.email, None)
                self.users.by_email[new_email] = user_id
                user.email = new_email
            user.role = new_role
            return self._clone(user)

    def delete_user(self, user_id):
        with self._lock:
            user = self.users.items.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))

            for project in self.projects.items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")

            for tid in self.tasks.by_assignee.get(user_id, set()):
                task = self.tasks.items.get(tid)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks assigned")

            del self.users.items[user_id]
            self.users.by_username.pop(user.username, None)
            self.users.by_email.pop(user.email, None)
            return None

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        name = self._validate_nonempty(name, "project name")
        self._validate_dates(start_date, end_date)
        with self._lock:
            if owner_id not in self.users.items:
                raise NotFoundError("owner {0} not found".format(owner_id))
            pid = self._new_id()
            project = Project(
                id=pid,
                name=name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
            )
            self.projects.items[pid] = project
            return self._clone(project)

    def get_project(self, project_id):
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))
            return self._clone(project)

    def list_projects(self):
        with self._lock:
            ordered = sorted(self.projects.items.values(), key=lambda p: p.id)
            return [self._clone(p) for p in ordered]

    def update_project(self, project_id, name=None, start_date=None, end_date=None, description=None):
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))

            new_name = project.name
            if name is not None:
                new_name = self._validate_nonempty(name, "project name")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return self._clone(project)

    def delete_project(self, project_id):
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))

            for tid in list(self.tasks.by_project.get(project_id, [])):
                self._remove_task_internal(tid)
            self.tasks.by_project.pop(project_id, None)

            for mid in list(self.messages.by_project.get(project_id, [])):
                self._remove_message_internal(mid)
            self.messages.by_project.pop(project_id, None)

            del self.projects.items[project_id]
            return None

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        title = self._validate_nonempty(title, "task title")
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))
            if assignee_id is not None and assignee_id not in self.users.items:
                raise NotFoundError("assignee {0} not found".format(assignee_id))
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot be before project start")

            tid = self._new_id()
            task = Task(
                id=tid,
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks.items[tid] = task
            self.tasks.by_project.setdefault(project_id, []).append(tid)
            if assignee_id is not None:
                self.tasks.by_assignee.setdefault(assignee_id, set()).add(tid)
            return self._clone(task)

    def get_task(self, task_id):
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            return self._clone(task)

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = self.tasks.by_project.get(project_id, [])
            tasks = [self.tasks.items[i] for i in ids if i in self.tasks.items]
            tasks.sort(key=lambda t: t.id)
            return [self._clone(t) for t in tasks]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            if user_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(user_id))
            ids = self.tasks.by_assignee.get(user_id, set())
            tasks = [self.tasks.items[i] for i in ids if i in self.tasks.items]
            tasks.sort(key=lambda t: t.id)
            return [self._clone(t) for t in tasks]

    def assign_task(self, task_id, assignee_id):
        return self._apply_assignment(task_id, assignee_id)

    def reassign_task(self, task_id, assignee_id):
        return self._apply_assignment(task_id, assignee_id)

    def unassign_task(self, task_id):
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            self._set_assignee(task, None)
            return self._clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if deadline is not None:
                project = self.projects.items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot be before project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id, status):
        if not isinstance(status, TaskStatus):
            raise ValidationError("status must be a TaskStatus")
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return self._clone(task)

    # -- task internals -----------------------------------------------------
    def _apply_assignment(self, task_id, assignee_id):
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if assignee_id not in self.users.items:
                raise NotFoundError("assignee {0} not found".format(assignee_id))
            self._set_assignee(task, assignee_id)
            return self._clone(task)

    def _set_assignee(self, task, new_assignee_id):
        old = task.assignee_id
        if old == new_assignee_id:
            return
        if old is not None:
            bucket = self.tasks.by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self.tasks.by_assignee.setdefault(new_assignee_id, set()).add(task.id)

    def _remove_task_internal(self, task_id):
        task = self.tasks.items.pop(task_id, None)
        if task is None:
            return
        bucket = self.tasks.by_project.get(task.project_id)
        if bucket is not None and task_id in bucket:
            bucket.remove(task_id)
        if task.assignee_id is not None:
            assignee_bucket = self.tasks.by_assignee.get(task.assignee_id)
            if assignee_bucket is not None:
                assignee_bucket.discard(task_id)
        for mid in list(self.messages.by_task.get(task_id, [])):
            self._remove_message_internal(mid)
        self.messages.by_task.pop(task_id, None)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None, attachments=None, parent_id=None):
        if (project_id is None) == (task_id is None):
            raise ValidationError("exactly one of project_id or task_id is required")
        with self._lock:
            if author_id not in self.users.items:
                raise NotFoundError("author {0} not found".format(author_id))
            if project_id is not None and project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            if task_id is not None and task_id not in self.tasks.items:
                raise NotFoundError("task {0} not found".format(task_id))

            attachment_objs = self._build_attachments(attachments, author_id)
            text = body if isinstance(body, str) else ""
            if not text.strip() and not attachment_objs:
                raise ValidationError("message must have a body or attachments")

            if parent_id is not None and parent_id not in self.messages.items:
                raise NotFoundError("parent message {0} not found".format(parent_id))

            mid = self._new_id()
            message = Message(
                id=mid,
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=self._now(),
                edited_at=None,
            )
            self.messages.items[mid] = message
            if project_id is not None:
                self.messages.by_project.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self.messages.by_task.setdefault(task_id, []).append(mid)
            return self._clone(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self.messages.items.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            text = new_body if isinstance(new_body, str) else ""
            if not text.strip() and not message.attachments:
                raise ValidationError("message body cannot be empty")
            message.body = text
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(self, message_id, user_id, filename, data):
        with self._lock:
            message = self.messages.items.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != user_id:
                raise AuthorizationError("only the author may attach files")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename must be a non-empty string")
            size = len(data) if data is not None else 0
            attachment = Attachment(
                filename=filename,
                size=size,
                uploaded_by=user_id,
                uploaded_at=self._now(),
            )
            message.attachments.append(attachment)
            return self._clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            if project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = self.messages.by_project.get(project_id, [])
            msgs = [self.messages.items[i] for i in ids if i in self.messages.items]
            msgs.sort(key=lambda m: m.id)
            return [self._clone(m) for m in msgs]

    def list_messages_by_task(self, task_id):
        with self._lock:
            if task_id not in self.tasks.items:
                raise NotFoundError("task {0} not found".format(task_id))
            ids = self.messages.by_task.get(task_id, [])
            msgs = [self.messages.items[i] for i in ids if i in self.messages.items]
            msgs.sort(key=lambda m: m.id)
            return [self._clone(m) for m in msgs]

    def delete_message(self, message_id, user_id):
        with self._lock:
            message = self.messages.items.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete this message")
            self._remove_message_internal(message_id)
            return None

    # -- messaging internals ------------------------------------------------
    def _build_attachments(self, attachments, author_id):
        objs = []
        if attachments:
            now = self._now()
            for item in attachments:
                filename, data = item
                size = len(data) if data is not None else 0
                objs.append(
                    Attachment(
                        filename=filename,
                        size=size,
                        uploaded_by=author_id,
                        uploaded_at=now,
                    )
                )
        return objs

    def _remove_message_internal(self, message_id):
        message = self.messages.items.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            bucket = self.messages.by_project.get(message.project_id)
            if bucket is not None and message_id in bucket:
                bucket.remove(message_id)
        if message.task_id is not None:
            bucket = self.messages.by_task.get(message.task_id)
            if bucket is not None and message_id in bucket:
                bucket.remove(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _user_tasks(self, user_id):
        ids = self.tasks.by_assignee.get(user_id, set())
        return [self.tasks.items[i] for i in ids if i in self.tasks.items]

    def _user_scores(self, user_id):
        ids = self.performance.by_ratee.get(user_id, [])
        return [self.performance.ratings[i].score for i in ids if i in self.performance.ratings]

    @staticmethod
    def _completion_durations(tasks):
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append((task.completed_at - task.started_at).total_seconds())
        return durations

    def get_completion_rate(self, user_id):
        with self._lock:
            if user_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(user_id))
            tasks = self._user_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            if user_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(user_id))
            durations = self._completion_durations(self._user_tasks(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if rater_id not in self.users.items:
                raise NotFoundError("rater {0} not found".format(rater_id))
            if ratee_id not in self.users.items:
                raise NotFoundError("ratee {0} not found".format(ratee_id))
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int) or score < 1 or score > 5:
                raise ValidationError("score must be an integer between 1 and 5")
            if task_id is not None and task_id not in self.tasks.items:
                raise NotFoundError("task {0} not found".format(task_id))

            rid = self._new_id()
            rating = Rating(
                id=rid,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.ratings[rid] = rating
            self.performance.by_ratee.setdefault(ratee_id, []).append(rid)
            return self._clone(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            if user_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(user_id))
            ids = self.performance.by_ratee.get(user_id, [])
            ratings = [self.performance.ratings[i] for i in ids if i in self.performance.ratings]
            ratings.sort(key=lambda r: r.id)
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count) if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            if user_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(user_id))
            tasks = self._user_tasks(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            durations = self._completion_durations(tasks)
            scores = self._user_scores(user_id)
            rating_count = len(scores)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": (sum(durations) / len(durations)) if durations else None,
                "rating_count": rating_count,
                "rating_average": (sum(scores) / rating_count) if rating_count else 0.0,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id):
        with self._lock:
            if project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = self.tasks.by_project.get(project_id, [])
            tasks = [self.tasks.items[i] for i in ids if i in self.tasks.items]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]

            now = self._now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {"total": 0, "completed": 0, "in_progress": 0, "not_started": 0},
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1
                elif task.status == TaskStatus.IN_PROGRESS:
                    bucket["in_progress"] += 1
                else:
                    bucket["not_started"] += 1
            for bucket in per_assignee.values():
                bucket["completion_rate"] = (
                    bucket["completed"] / bucket["total"] if bucket["total"] else 0.0
                )

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completed_tasks": completed,
                "in_progress_tasks": status_counts[TaskStatus.IN_PROGRESS.value],
                "not_started_tasks": status_counts[TaskStatus.NOT_STARTED.value],
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))

            if project_id is None:
                user_ids = sorted(self.users.items.keys())
            else:
                assignees = set()
                for tid in self.tasks.by_project.get(project_id, []):
                    task = self.tasks.items.get(tid)
                    if task is not None and task.assignee_id is not None:
                        assignees.add(task.assignee_id)
                user_ids = sorted(assignees)

            rows = []
            for uid in user_ids:
                if uid not in self.users.items:
                    continue
                rows.append(self._performance_row(uid, project_id))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            user = self.users.items.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))
            tasks = self._user_tasks(user_id)
            tasks.sort(key=lambda t: t.id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            durations = self._completion_durations(tasks)
            scores = self._user_scores(user_id)
            rating_count = len(scores)

            task_rows = [
                {
                    "id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                    "assignee_id": t.assignee_id,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in tasks
            ]

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": (sum(durations) / len(durations)) if durations else None,
                "rating_count": rating_count,
                "rating_average": (sum(scores) / rating_count) if rating_count else 0.0,
                "tasks": task_rows,
            }

    def _performance_row(self, user_id, project_id=None):
        tasks = self._user_tasks(user_id)
        if project_id is not None:
            tasks = [t for t in tasks if t.project_id == project_id]
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = self._completion_durations(tasks)
        scores = self._user_scores(user_id)
        rating_count = len(scores)
        user = self.users.items.get(user_id)
        return {
            "user_id": user_id,
            "username": user.username if user is not None else "",
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": (sum(durations) / len(durations)) if durations else None,
            "rating_count": rating_count,
            "rating_average": (sum(scores) / rating_count) if rating_count else 0.0,
        }

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report, report_format):
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if report_format == ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    @staticmethod
    def _csv_cell(value):
        if value is None:
            return ""
        if isinstance(value, datetime):
            return value.isoformat()
        if isinstance(value, bool):
            return str(value)
        return value

    def _report_to_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            columns = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(columns)
            for row in report.get("rows", []):
                writer.writerow([self._csv_cell(row.get(col)) for col in columns])

        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            columns = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "in_progress_tasks",
                "not_started_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(columns)
            writer.writerow([self._csv_cell(report.get(col)) for col in columns])
            writer.writerow([])
            writer.writerow(["task_id", "title", "status", "assignee_id"])
            for task in report.get("tasks", []):
                writer.writerow(
                    [
                        self._csv_cell(task.get("id")),
                        self._csv_cell(task.get("title")),
                        self._csv_cell(task.get("status")),
                        self._csv_cell(task.get("assignee_id")),
                    ]
                )
        else:
            header = []
            values = []
            for key, value in report.items():
                if isinstance(value, dict):
                    for sub_key, sub_value in value.items():
                        header.append("{0}.{1}".format(key, sub_key))
                        values.append(self._csv_cell(sub_value))
                elif isinstance(value, (list, tuple)):
                    header.append(key)
                    values.append(len(value))
                else:
                    header.append(key)
                    values.append(self._csv_cell(value))
            writer.writerow(header)
            writer.writerow(values)

        return output.getvalue()

    def _report_to_pdf(self, report):
        lines = self._report_to_text_lines(report)
        return self._build_pdf(lines)

    @staticmethod
    def _report_to_text_lines(report):
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append("  {0}: {1}".format(sub_key, sub_value))
            elif isinstance(value, (list, tuple)):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines

    @staticmethod
    def _pdf_escape(text):
        text = str(text)
        return text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")

    def _build_pdf(self, lines):
        content_parts = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
        first = True
        for line in lines:
            escaped = self._pdf_escape(line)
            if first:
                content_parts.append("({0}) Tj".format(escaped))
                first = False
            else:
                content_parts.append("T*")
                content_parts.append("({0}) Tj".format(escaped))
        content_parts.append("ET")
        content = "\n".join(content_parts).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
            b"<< /Length "
            + str(len(content)).encode("ascii")
            + b" >>\nstream\n"
            + content
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        out = bytearray()
        out += b"%PDF-1.4\n"
        offsets = []
        for index, obj in enumerate(objects, start=1):
            offsets.append(len(out))
            out += str(index).encode("ascii") + b" 0 obj\n" + obj + b"\nendobj\n"

        xref_position = len(out)
        size = len(objects) + 1
        out += b"xref\n"
        out += b"0 " + str(size).encode("ascii") + b"\n"
        out += b"0000000000 65535 f \n"
        for offset in offsets:
            out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        out += b"trailer\n<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
        out += b"startxref\n" + str(xref_position).encode("ascii") + b"\n%%EOF"
        return bytes(out)


